#!/usr/bin/env python3
import csv
import os
from datetime import datetime
from pathlib import Path

# Read and clean all CSV files
csv_dir = Path("/data/csv")
all_rows = []
headers = None

for csv_file in sorted(csv_dir.glob("*.csv")):
    print(f"Processing {csv_file.name}...")

    with open(csv_file, 'r') as f:
        reader = csv.DictReader(f)

        for i, row in enumerate(reader):
            # Skip duplicate headers (rows where values match header names)
            if row.get('event_id') == 'event_id':
                print(f"  Skipping duplicate header at row {i}")
                continue

            # Clean the row
            cleaned_row = {}

            # event_id
            if row.get('event_id'):
                cleaned_row['event_id'] = row['event_id'].strip()
            else:
                continue  # Skip rows with missing event_id

            # event_ts - handle different date formats
            ts = row.get('event_ts', '').strip()
            if ts:
                try:
                    # Try ISO format first
                    if 'T' in ts:
                        dt = datetime.fromisoformat(ts.replace('Z', '+00:00'))
                    else:
                        # Try DD/MM/YYYY format
                        dt = datetime.strptime(ts, '%d/%m/%Y')
                    cleaned_row['event_ts'] = dt.isoformat()
                except:
                    print(f"  Warning: Could not parse date '{ts}' in {csv_file.name}")
                    continue
            else:
                continue  # Skip rows with missing timestamp

            # user_id
            if row.get('user_id'):
                cleaned_row['user_id'] = row['user_id'].strip()
            else:
                continue  # Skip rows with missing user_id

            # event_type
            if row.get('event_type'):
                cleaned_row['event_type'] = row['event_type'].strip()
            else:
                continue  # Skip rows with missing event_type

            # value - handle missing values
            value_str = row.get('value', '').strip()
            if value_str and value_str not in ['N/A', 'null', '']:
                try:
                    cleaned_row['value'] = float(value_str)
                except:
                    print(f"  Warning: Could not parse value '{value_str}' in {csv_file.name}, setting to NULL")
                    cleaned_row['value'] = None
            else:
                cleaned_row['value'] = None

            all_rows.append(cleaned_row)

# Write cleaned data to temp file
output_file = Path("/tmp/events_clean.csv")
print(f"\nWriting {len(all_rows)} cleaned rows to {output_file}...")

with open(output_file, 'w', newline='') as f:
    fieldnames = ['event_id', 'event_ts', 'user_id', 'event_type', 'value']
    writer = csv.DictWriter(f, fieldnames=fieldnames)
    writer.writeheader()
    writer.writerows(all_rows)

print(f"✓ Cleaned data written to {output_file}")
print(f"Total records: {len(all_rows)}")

# Show preview
print("\nPreview of cleaned data:")
with open(output_file, 'r') as f:
    for i, line in enumerate(f):
        if i < 6:
            print(line.rstrip())
        else:
            break

